file_io_pass.script:
const plan = { id: 'test', boundary: 'test-boundary', content: 'hello' }
await Bun.write('/tmp/test-plan-io.json', JSON.stringify(plan, null, 2))
const result = await Bun.file('/tmp/test-plan-io.json').json()
console.log(result.id === 'test' ? 'PASS' : 'FAIL')

jsonl_append_pass.script:
const record = { plan_id: 'test', executor: 'test', validation_passed: true, recorded_at: new Date().toISOString() }
const line = JSON.stringify(record) + '\n'
await Bun.write('/tmp/test-wave.jsonl', line, { flag: 'a' })
const content = await Bun.file('/tmp/test-wave.jsonl').text()
const parsed = JSON.parse(content.trim())
console.log(parsed.plan_id === 'test' ? 'PASS' : 'FAIL')

sha256_dedup_pass.script:
const data = JSON.stringify({ affected_files: ['test.ts'], language: 'ts' })
const hash1 = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(data)).then(...)
const hash2 = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(data)).then(...)
console.log(hash1 === hash2 ? 'PASS' : 'FAIL')

effect_runtime_fail.script:
import { Effect, Layer } from 'effect'
import { AppFileSystem } from '@opencode-ai/core/filesystem'
Effect.gen(function* () {
  const fs = yield* AppFileSystem.Service
  yield* fs.writeFileString('/tmp/effect-test.txt', 'hello\n')
  const content = yield* fs.readFileString('/tmp/effect-test.txt')
  console.log(content === 'hello' ? 'PASS' : 'FAIL')
}).pipe(Effect.provide(Layer.mergeAll(AppFileSystem.Default)), Effect.runPromise)
